{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "agent-eval-cost-budget-policy-output",
  "required": [
    "nightly_full_suite_size",
    "per_pr_subset_size",
    "weekly_adversarial_size",
    "cost_ceiling_daily_usd",
    "fallback_judge_model",
    "forbidden_seen"
  ],
  "properties": {
    "nightly_full_suite_size": {
      "description": "Examples in nightly run."
    },
    "per_pr_subset_size": {
      "description": "Examples in PR run (\u226420% of full)."
    },
    "weekly_adversarial_size": {
      "description": "Examples in adversarial run."
    },
    "cost_ceiling_daily_usd": {
      "description": "Daily cap."
    },
    "fallback_judge_model": {
      "description": "Cheaper judge model id."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
